Parallel processing

Single bootstrap sample

library(doParallel)

gal &lt;- galaxies
n &lt;- length(gal)

c1 &lt;- makeCluster(2)
registerDoParallel(c1)

system.time( {
  result_parallel &lt;- foreach(i = 1:1000, .combine = c) %dopar% {
  samp &lt;- sample(gal, n, replace = TRUE)
  med &lt;- median(samp)
  }
})

   user  system elapsed 
   0.19    0.03    0.32 



stopCluster(c1)



1000 bootstrap samples

c2 &lt;- makeCluster(2)
registerDoParallel(c2)

system.time( {
  results_large_p &lt;- foreach(i = 1:100, .combine = c) %dopar% {
  vec &lt;- numeric(1000)

  for (j in 1:1000) {
    s &lt;- sample(gal, n, replace = TRUE)
    vec[j] &lt;- median(s)
  }

  }
})

   user  system elapsed 
   0.08    0.00    2.47 



stopCluster(c2)

Serial processing

Single bootstrap sample

system.time( {
  result_serial &lt;- foreach(i = 1:1000, .combine = c) %do% {
    boot_samp &lt;- sample(gal, n, replace = TRUE)
    med_samp &lt;- median(boot_samp)
  }
})

   user  system elapsed 
   0.22    0.02    0.23 




1000 bootstrap samples

system.time( {
  results_large_s &lt;- foreach(i = 1:100, .combine = c) %do% {
  vec &lt;- numeric(1000)

  for (j in 1:1000) {
    s &lt;- sample(gal, n, replace = TRUE)
    vec[j] &lt;- median(s)
  }

  }
})

   user  system elapsed 
   4.51    0.11    4.61 


From the results above, we see that the total run time for parallel processing is higher than for serial processing. However, with larger chunks we can see that using a parallel approach significantly decreases the processing time, thereby improving efficiency compared to serial processing.
